from kafka import KafkaConsumer
import json
import pickle
from typing import Dict, Any, Callable
import logging

class FinancialTransactionConsumer:
    def __init__(self, bootstrap_servers: str, group_id: str):
        self.consumer = KafkaConsumer(
            bootstrap_servers=bootstrap_servers,
            group_id=group_id,
            value_deserializer=self._deserialize_message,
            auto_offset_reset='earliest',
            enable_auto_commit=True
        )
        self.message_handlers: Dict[str, Callable] = {}
        self.logger = logging.getLogger(__name__)
    
    def _deserialize_message(self, message):
        try:
            if isinstance(message, bytes):
                return pickle.loads(message)
            return json.loads(message.decode('utf-8'))
        except Exception as e:
            self.logger.error(f"Failed to deserialize message: {e}")
            return None
    
    def register_handler(self, event_type: str, handler: Callable):
        self.message_handlers[event_type] = handler
    
    def process_message(self, message):
        try:
            if not message.value:
                return
            
            event_type = message.value.get('event_type')
            if not event_type:
                self.logger.warning("Message has no event_type")
                return
            
            handler = self.message_handlers.get(event_type)
            if not handler:
                self.logger.warning(f"No handler registered for event type: {event_type}")
                return
            
            handler(message.value)
            
        except Exception as e:
            self.logger.error(f"Error processing message: {e}")
    
    def start_consuming(self, topics: list):
        self.consumer.subscribe(topics)
        self.logger.info(f"Started consuming from topics: {topics}")
        
        try:
            for message in self.consumer:
                self.process_message(message)
        except KeyboardInterrupt:
            self.logger.info("Consumer stopped by user")
        except Exception as e:
            self.logger.error(f"Consumer error: {e}")
        finally:
            self.consumer.close()
    
    def stop_consuming(self):
        self.consumer.close()

# Example usage
def handle_payment_transaction(transaction_data):
    print(f"Processing payment transaction: {transaction_data['transaction_id']}")

def handle_refund_transaction(transaction_data):
    print(f"Processing refund transaction: {transaction_data['transaction_id']}")

# Initialize consumer
consumer = FinancialTransactionConsumer(
    bootstrap_servers='localhost:9092',
    group_id='financial-group'
)

# Register handlers
consumer.register_handler('payment', handle_payment_transaction)
consumer.register_handler('refund', handle_refund_transaction)

# Start consuming
